import React, { useEffect, useState, useRef } from "react";
import {
  Chart as ChartJS, ArcElement, Tooltip, Legend,
  CategoryScale, LinearScale, BarElement, Title
} from "chart.js";
import { Doughnut, Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(ArcElement, Tooltip, Legend, CategoryScale, LinearScale, BarElement, Title);

const periods = [
  { start: "08:00", end: "08:50" },
  { start: "08:50", end: "09:40" },
  { start: "10:00", end: "10:50" },
  { start: "10:50", end: "11:40" },
  { start: "12:30", end: "13:20" },
  { start: "13:20", end: "14:10" },
  { start: "14:10", end: "15:00" },
  { start: "15:00", end: "15:40" },
];

const getCurrentPeriod = (date) => {
  const hours = date.getHours();
  const minutes = date.getMinutes();
  const totalMins = hours * 60 + minutes;

  for (let i = 0; i < periods.length; i++) {
    const [sh, sm] = periods[i].start.split(":").map(Number);
    const [eh, em] = periods[i].end.split(":").map(Number);
    const startMins = sh * 60 + sm;
    const endMins = eh * 60 + em;
    if (totalMins >= startMins && totalMins < endMins) {
      return i;
    }
  }
  return -1;
};

const Dashboard = () => {
  const [stats, setStats] = useState(null);
  const [selectedPeriod, setSelectedPeriod] = useState(null);
  const [currentTime, setCurrentTime] = useState(new Date());
  const prevPeriodRef = useRef(null);

  const fetchStats = async (period = null) => {
    const url = period !== null
      ? `/api/dashboard-stats?period=${period}`
      : `/api/dashboard-stats`;
    const res = await fetch(url);
    const data = await res.json();
    setStats(data);
    if (period === null) {
      prevPeriodRef.current = data.currentPeriod;
    }
  };

  // Initial + time updater
  useEffect(() => {
    fetchStats(); // Initial fetch

    const timeUpdater = setInterval(() => {
      setCurrentTime(new Date());
    }, 1000);

    return () => clearInterval(timeUpdater);
  }, []);

  // Period-based auto fetch logic
  useEffect(() => {
    let autoInterval = null;

    if (selectedPeriod === null) {
      autoInterval = setInterval(() => {
        const now = new Date();
        const currentPeriod = getCurrentPeriod(now);

        if (currentPeriod !== -1 && currentPeriod !== prevPeriodRef.current) {
          fetchStats();
        }
      }, 60000); // check every 1 min
    }

    return () => {
      if (autoInterval) clearInterval(autoInterval);
    };
  }, [selectedPeriod]);

  // Manual period fetch
  useEffect(() => {
    if (selectedPeriod !== null) {
      fetchStats(selectedPeriod);
    } else {
      fetchStats(); // Revert to auto
    }
  }, [selectedPeriod]);

  if (!stats) return <div>Loading...</div>;

  const donutOptions = {
    cutout: "60%",
    plugins: {
      legend: { position: "bottom", labels: { boxWidth: 12, padding: 10 } },
      tooltip: { enabled: true },
    },
  };

  const getDonutData = (labels, values, colors) => ({
    labels,
    datasets: [{
      data: values,
      backgroundColor: colors,
      borderWidth: 0,
    }],
  });

  const barData = {
    labels: Object.keys(stats.barChart),
    datasets: [{
      label: "Free Rooms",
      data: Object.values(stats.barChart),
      backgroundColor: ["#2196F3", "#8BC34A", "#FF9800", "#03A9F4", "#E91E63", "#FFC107"],
      barThickness: 30,
    }],
  };

  return (
    <div className="dashboard-container">
      <h2 className="dashboard-heading">Classroom Dashboard</h2>

      <div className="time-row">
        <div><strong>Time:</strong> {currentTime.toLocaleTimeString()}</div>
        <div><strong>Period:</strong> {stats.periodLabel}</div>
        <div>
          <strong>Manual:</strong>{" "}
          <select
            value={selectedPeriod ?? ""}
            onChange={(e) =>
              setSelectedPeriod(e.target.value === "" ? null : parseInt(e.target.value))
            }
          >
            <option value="">Auto</option>
            {[...Array(8)].map((_, i) => (
              <option key={i} value={i}>Period {i + 1}</option>
            ))}
          </select>
        </div>
      </div>

      <div className="dashboard-grid">
        <div className="card small-chart">
          <h4>Free vs Occupied</h4>
          <Doughnut
            data={getDonutData(["Occupied", "Free"], [stats.pieChart.occupied, stats.pieChart.free], ["#f44336", "#4CAF50"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Projector Rooms</h4>
          <Doughnut
  data={getDonutData(["Projectors", "Others"],[stats.freeProjectorRoomNames.length,stats.resources.projectorRooms - stats.freeProjectorRoomNames.length
    ],
    ["#FF9800", "#e0e0e0"]
  )}
  options={donutOptions}
/>

        </div>

        <div className="card small-chart">
          <h4>Free Labs</h4>
          <Doughnut
            data={getDonutData(["Labs", "Others"], [stats.resources.labs, stats.resources.totalRooms - stats.resources.labs], ["#9C27B0", "#e0e0e0"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Free Classrooms</h4>
          <Doughnut
            data={getDonutData(["Classrooms", "Others"], [stats.resources.classrooms, stats.resources.totalRooms - stats.resources.classrooms], ["#3F51B5", "#e0e0e0"])}
            options={donutOptions}
          />
        </div>

        <div className="card small-chart">
          <h4>Not Occupied</h4>
          <Doughnut
            data={getDonutData(["Not Occupied", "Occupied"], [stats.resources.totalRooms - stats.pieChart.occupied, stats.pieChart.occupied], ["#009688", "#f44336"])}
            options={donutOptions}
          />
        </div>

        <div className="card full-width">
          <h4 style={{ marginLeft: '10px' }}>Free Rooms Per Weekday</h4>
          <div className="bar-info-container">
            <div className="bar-chart">
              <Bar
                data={barData}
                options={{
                  responsive: true,
                  maintainAspectRatio: false,
                  plugins: { legend: { display: false } },
                  scales: { y: { beginAtZero: true } },
                }}
              />
            </div>
            <div className="info-panel">
              <p><strong>Total rooms:</strong> {stats.resources.totalRooms}</p>
              <p><strong>Total labs:</strong> {stats.resources.labs}</p>
              <p><strong>Total free rooms:</strong> {stats.pieChart.free}</p>
              <p><strong>Total projector free:</strong> {stats.resources.projectorRooms}</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
